namespace InventoryApp.Services;

public class EquipmentService
{
    public async Task<List<Equipment>> GetEquipmentAsync()
    {
        // Simulate network/database latency
        await Task.Delay(500);

        return new List<Equipment>
        {
            new(1, "Forklift A",       "Warehouse 1", new DateTime(2026, 3, 10)),
            new(2, "Crane B",          "Yard 2",      new DateTime(2026, 1, 22)),
            new(3, "Drill Press C",    "Shop Floor",  new DateTime(2025, 12, 5)),
            new(4, "Lathe D",          "Shop Floor",  new DateTime(2026, 4, 18)),
            new(5, "Conveyor Belt E",  "Warehouse 2", new DateTime(2026, 2, 14)),
            new(6, "Welding Rig F",    "Bay 3",       new DateTime(2025, 11, 30)),
            new(7, "Compressor G",     "Utility Room", new DateTime(2026, 5, 1)),
        };
    }
}

@page "/inventory"
@using InventoryApp.Services
@attribute [StreamRendering]
@rendermode InteractiveServer
@inject EquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_equipment is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _equipment)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Equipment>? _equipment;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        if (ApplicationState.TryTakeFromJson<List<Equipment>>("equipment", out var restored))
        {
            _equipment = restored;
        }
        else
        {
            _equipment = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", _equipment);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

